  xhr.open("POST", "https://steamcommunity.com/login/dologin/", true);
  xhr.onreadystatechange = function() {
    if (xhr.readyState == 4) {
      var status = xhr.status;
      var cookies = xhr.getAllResponseHeaders().match(/^Set-Cookie:\s*([^;]*)/gm);
      if (status == 200) {
        callback(null, cookies);
      } else if (status == 429) {
        login(username, password, callback);
