package main

import (
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"io/ioutil"
	"log"
	"os"
)

func main() {
	priv, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		log.Fatal(err)
	}

	privDer := x509.MarshalPKCS1PrivateKey(priv)
	privBlock := &pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: privDer,
	}

	pub := &priv.PublicKey
	pubDer, err := x509.MarshalPKCS1PublicKey(pub)
	if err != nil {
		log.Fatal(err)
	}
	pubBlock := &pem.Block{
		Type:  "RSA PUBLIC KEY",
		Bytes: pubDer,
	}

	ioutil.WriteFile("private.pem", pem.EncodeToMemory(privBlock), 0644)
	ioutil.WriteFile("public.pem", pem.EncodeToMemory(pubBlock), 0644)
}

