func GenerateKey(typ string, size int, rand io.Reader) (interface{}, error) {
	switch typ {
	case "RSA PRIVATE KEY":
		return rsa.GenerateKey(rand, size)
	case "EC PRIVATE KEY":
		var curve elliptic.Curve
		switch size {
		case 256:
			curve = elliptic.P256()
		case 384:
			curve = elliptic.P384()
		case 521:
			curve = elliptic.P521()
		default:
			return nil, fmt.Errorf("invalid key size %d", size)
		}
		priv, x, y, err := elliptic.GenerateKey(curve, rand)
		if err != nil {
			return nil, err
		}
		return &ecPrivateKey{curve: curve, x: x, y: y, d: priv}, nil
	default:
		return nil, fmt.Errorf("unsupported key type %q", typ)
	}
}

