public static RSAPublicKey getOrGenerateKeyPair(String keyName, KeyStore keyStore, String password, SecureRandom random) throws KeyStoreException, NoSuchAlgorithmException, UnrecoverableEntryException, CertificateEncodingException, IOException {

    RSAPublicKey rsaPublicKey;
    if (keyStore.containsAlias(keyName)) {
        KeyStore.PrivateKeyEntry entry = (KeyStore.PrivateKeyEntry) keyStore.getEntry(keyName, new KeyStore.PasswordProtection(password.toCharArray()));
        rsaPublicKey = (RSAPublicKey) entry.getCertificate().getPublicKey();
    } else {
        KeyPair keyPair = RSAKeyGen.generateRSAKeyPair(random, 2048);
        X509Certificate certificate = RSAKeyGen.generateCertificate(keyPair, keyName, 10000, password, password);
        keyStore.setKeyEntry(keyName, keyPair.getPrivate(), password.toCharArray(), new Certificate[] { certificate });
        keyStore.store(new FileOutputStream(new File(keyStore.getType())), password.toCharArray());
        rsaPublicKey = (RSAPublicKey) certificate.getPublicKey();
    }
    return rsaPublicKey;
}

