def validate_feature_tags(tags):
    """
    tags: list of tags to validate
    """
    for tag in tags:
        if tag.startswith('bugzilla/'):
            bug_id = tag[8:]
            if not bug_id.isdigit():
                return False
        elif tag.startswith('version/'):
            version = tag[8:]
            if version not in VERSIONS:
                return False
        elif tag in TAG_REGISTRY:
            pass
        else:
            return False
    return True

