def hierarchical_tile(tile_file, tiling_file):
    """
    This function reads a tile file and a tiling file and writes a new
    tile file that reflects the tiling information from the tiling file.
    """
    tile_file = open(tile_file, "r")
    tiling_file = open(tiling_file, "r")

    tile_file_lines = tile_file.readlines()
    tiling_file_lines = tiling_file.readlines()

    tiling_file.close()
    tile_file.close()

    tiling_file = open(tiling_file, "w")

    for i in range(len(tile_file_lines)):
        if tile_file_lines[i].startswith("Tile"):
            tiling_file.write(tile_file_lines[i])
            if i+1 < len(tile_file_lines):
                if tile_file_lines[i+1].startswith("Tile"):
                    tiling_file.write(tile_file_lines[i+1])
                    if i+2 < len(tile_file_lines):
                        if tile_file_lines[i+2].startswith("Tile"):
                            tiling_file.write(tile_file_lines[i+2])

    tiling_file.close()

