# Write a Ruby function to generate an RSS feed from a list of results and save it to a file.
def generate_rss(results)
  xml = Builder::XmlMarkup.new
  xml.instruct!
  xml.rss(:version => "2.0", :xmlns => "http://www.w3.org/1999/xhtml") {
    xml.channel {
      xml.title "RSS Feed"
      xml.description "RSS Feed Description"
      xml.link "http://www.example.com"
      results.each do |result|
        xml.item {
          xml.title result.title
          xml.description result.description
          xml.pubDate result.pub_date
          xml.link result.link
        }
      end
    }
  }
  File.open("rss_feed.xml", "w") do |f|
    f.write xml.target!
  end
end

