func parseMPLS(s string) ([]uint32, error) {
	labels := strings.Split(s, "/")
	if len(labels) == 0 {
		return nil, errors.New("missing labels")
	}
	if len(labels) > 1 && labels[len(labels)-1] == "" {
		return nil, errors.New("trailing slash")
	}
	for _, l := range labels {
		label, err := strconv.ParseUint(l, 10, 20)
		if err != nil {
			return nil, fmt.Errorf("invalid label %q: %v", l, err)
		}
		if label > 0xfffff {
			return nil, fmt.Errorf("invalid label %q: out of range", l)
		}
	}
	return labels, nil
}

