func (rd *RD) Parse(rdStr string) error {
	rd.ASN = 0
	rd.IP = nil
	rd.IPMask = 0
	rd.ASNMask = 0

	// RD is of the form <asn>:<ip> or <asn>:<ip>/<mask>
	rdParts := strings.Split(rdStr, ":")
	if len(rdParts) != 2 {
		return fmt.Errorf("invalid Route Distinguisher format: %s", rdStr)
	}

	// Try to parse the ASN.
	asn, err := strconv.ParseUint(rdParts[0], 10, 32)
	if err != nil {
		return fmt.Errorf("invalid Route Distinguisher format: %s", rdStr)
	}
	rd.ASN = uint32(asn)

	// Try to parse the IP.
	ipParts := strings.Split(rdParts[1], "/")
	if len(ipParts) == 1 {
		// If there is no mask, the IP is the only part.
		ip := net.ParseIP(ipParts[0])
		if ip == nil {
			return fmt.Errorf("invalid IP address: %s", ipParts[0])
		}
		rd.IP = ip
	} else if len(ipParts) == 2 {
		// If there is a mask, the IP and mask are the only parts.
		ip := net.ParseIP(ipParts[0])
		if ip == nil {
			return fmt.Errorf("invalid IP address: %s", ipParts[0])
		}
		mask, err := strconv.ParseUint(ipParts[1], 10, 8)
		if err != nil {
			return fmt.Errorf("invalid IP mask: %s", ipParts[1])
		}
		rd.IP = ip
		rd.IPMask = uint8(mask)
	} else {
		return fmt.Errorf("invalid Route Distinguisher format: %s", rdStr)
	}

	return nil
}

