	stmt, err := db.Prepare("SELECT * FROM baskets WHERE name = ?")
	if err != nil {
		return nil, err
	}
	defer stmt.Close()

	row := stmt.QueryRow(basketName)

	basket := new(Basket)
	err = row.Scan(&basket.ID, &basket.Name)
	if err != nil {
		return nil, err
	}

	return basket, nil
}

func insertBasket(basket *Basket) error {
	stmt, err := db.Prepare("INSERT INTO baskets (name) VALUES (?)")
	if err != nil {
		return err
	}
	defer stmt.Close()

	res, err := stmt.Exec(basket.Name)
	if err != nil {
		return err
	}

	id, err := res.LastInsertId()
	if err != nil {
		return err
	}

	basket.ID = int(id)
	return nil
}

