// Package basket provides a basket implementation.
package basket

import (
	"errors"
	"fmt"
	"strings"
)

// A Basket represents a basket.
type Basket struct {
	Name    string
	Enabled bool
}

// NewBasket creates a new basket with a given name and optional configuration.
//
// An error is returned if the name is invalid.
func NewBasket(name string, enabled bool) (*Basket, error) {
	if !validName.MatchString(name) {
		return nil, errors.New("invalid basket name")
	}
	return &Basket{
		Name:    name,
		Enabled: enabled,
	}, nil
}

var validName = regexp.MustCompile("^[a-zA-Z0-9_-]{1,255}$")

