var refresh_select = function(select, settings) {
  // Clear columns
  select.wrapper.selected.innerHTML = "";
  select.wrapper.non_selected.innerHTML = "";

  // Add headers to columns
  if (settings.non_selected_header && settings.selected_header) {
    var non_selected_header = document.createElement("div");
    var selected_header = document.createElement("div");

    non_selected_header.className = "header";
    selected_header.className = "header";

    non_selected_header.innerText = settings.non_selected_header;
    selected_header.innerText = settings.selected_header;

    select.wrapper.non_selected.appendChild(non_selected_header);
    select.wrapper.selected.appendChild(selected_header);
  }

  // Get search value
  if (select.wrapper.search) {
    var search_value = select.wrapper.search.value.toLowerCase();
  }

  // Add options to columns
  for (var i = 0; i < select.options.length; i++) {
    var option = select.options[i];
    var option_text = option.text.toLowerCase();
    var option_value = option.value;
    var option_selected = option.selected;
    var option_disabled = option.disabled;

    // If search is enabled, filter out options that don't match
    if (search_value && search_value.length > 0) {
      if (option_text.indexOf(search_value) == -1) {
        continue;
      }
    }

    // If grouping is enabled, add option to the correct column
    if (settings.grouping) {
      if (option_selected) {
        var column = select.wrapper.selected;
      } else {
        var column = select.wrapper.non_selected;
      }
    } else {
      var column = select.wrapper.non_selected;
    }

    // Create option element
    var option_element = document.createElement("div");
    option_element.className = "option";
    option_element.innerText = option.text;
    option_element.value = option.value;

    // Add option to column
    column.appendChild(option_element);

    // Add event listeners
    option_element.addEventListener("click", function() {
      select.select_option(this);
    });

    option_element.addEventListener("mouseover", function() {
      select.wrapper.selected.classList.remove("selected");
      select.wrapper.non_selected.classList.remove("selected");
      this.classList.add("selected");
    });

    option_element.addEventListener("mouseout", function() {
      this.classList.remove("selected");
    });
  }
};

