function readFile(filePath, callback) {
  fs.readFile(filePath, 'utf8', (err, data) => {
    if (err) {
      logger.error('Failed to read file: ' + filePath, err);
      callback(500, 'Internal Server Error');
    } else {
      callback(200, data);
    }
  });
}

