function showAndHideMessage (message) {
	try {
		var messageElement = document.getElementById("message");
		messageElement.innerHTML = message;
		messageElement.style.display = "block";
		setTimeout(function () {
			messageElement.style.display = "none";
		}, 2000);
	} catch (e) {
		console.log(e);
	}
}

