function replaceWithForm(el) {
  const form = document.createElement('form');
  form.method = 'post';
  form.action = el.action;
  form.innerHTML = `
    <input type="hidden" name="_method" value="PUT">
    <input type="hidden" name="_csrf" value="${el._csrf}">
    <textarea name="body" rows="20" cols="50"></textarea>
    <input type="submit" value="Save">
    <input type="button" value="Cancel" onclick="replaceWithButton(this)">
  `;
  el.parentNode.replaceChild(form, el);
}

function replaceWithButton(el) {
  const button = document.createElement('button');
  button.innerHTML = 'Edit';
  button.onclick = () => replaceWithForm(this);
  el.parentNode.replaceChild(button, el);
}

