function updateDataEntry(entry, grades) {
  const gradeKeys = Object.keys(grades);
  const gradeValues = Object.values(grades);
  const gradeTypes = Object.entries(grades).map(([key, value]) => ({ key, value }));
  const gradeKeyIndex = gradeTypes.findIndex(({ key }) => key === entry.gradeType);
  const gradeValue = gradeValues[gradeKeyIndex];
  const gradeType = gradeTypes[gradeKeyIndex];
  const newEntry = { ...entry };
  if (gradeType.value === "image") {
    newEntry.gradeImage = gradeValue;
  } else {
    newEntry.gradeText = gradeValue;
  }
  return newEntry;
}

