function initWYSIWYG(settings) {
  var editor = document.getElementById('editor');
  var toolbar = document.getElementById('toolbar');
  var content = document.getElementById('content');

  // Initialize the editor with the given settings
  editor.value = settings.content;
  toolbar.innerHTML = settings.toolbar;
  content.innerHTML = settings.content;

  // Add event listeners to the editor
  editor.addEventListener('input', function() {
    content.innerHTML = editor.value;
  });

  // Add event listeners to the toolbar
  toolbar.addEventListener('click', function(event) {
    var target = event.target;
    var command = target.getAttribute('data-command');

    if (command) {
      document.execCommand(command);
    }
  });
}

