$(document).ready(function() {
    var $modal = $("#modal");
    var $checkbox = $("#inverted");
    var $input = $("#input");
    var $select = $("#select");
    var $text = $("#text");
    var $invertedText = $("#inverted-text");

    $input.on("input", function() {
        $text.text($input.val());
    });

    $select.on("change", function() {
        $text.text($select.val());
    });

    $checkbox.on("change", function() {
        $text.toggleClass("inverted", $checkbox.is(":checked"));
        $invertedText.toggleClass("hidden", !$checkbox.is(":checked"));
    });

    $modal.on("show.bs.modal", function() {
        $text.text($input.val());
        $text.toggleClass("inverted", $checkbox.is(":checked"));
        $invertedText.toggleClass("hidden", !$checkbox.is(":checked"));
    });
});

