function updateChat(message) {
    const chat = document.querySelector('#chat');
    const text = document.createElement('p');
    text.innerText = message.text;
    text.classList.add('message');
    if (message.user === 'me') {
        text.classList.add('my-message');
    }
    if (message.user === 'them') {
        text.classList.add('their-message');
    }
    if (message.type === 'text') {
        chat.appendChild(text);
    }
    if (message.type === 'action') {
        const action = document.createElement('i');
        action.classList.add('action');
        action.classList.add('fas');
        action.classList.add('fa-' + message.icon);
        action.classList.add('message');
        if (message.user === 'me') {
            action.classList.add('my-action');
        }
        if (message.user === 'them') {
            action.classList.add('their-action');
        }
        chat.appendChild(action);
    }
    if (message.type === 'mention') {
        const mention = document.createElement('b');
        mention.classList.add('mention');
        mention.classList.add('message');
        if (message.user === 'me') {
            mention.classList.add('my-mention');
        }
        if (message.user === 'them') {
            mention.classList.add('their-mention');
        }
        mention.innerText = message.user;
        text.appendChild(mention);
        chat.appendChild(text);
    }
    chat.scrollTop = chat.scrollHeight;
}

