.factory('Alert', ['$rootScope', '$filter', function ($rootScope, $filter) {
    return function (hdr, msg, cls, action, secondAlert, disableButtons, backdrop) {
        var scope = $rootScope.$new(), alertClass, local_backdrop;
        if (typeof backdrop === 'undefined') {
            local_backdrop = true;
        } else {
            local_backdrop = backdrop;
        }

        if (typeof cls === 'undefined') {
            alertClass = 'alert-info';
        } else {
            alertClass = cls;
        }

        if (typeof action === 'undefined') {
            action = 'OK';
        }

        if (typeof disableButtons === 'undefined') {
            disableButtons = false;
        }

        if (typeof secondAlert === 'undefined') {
            secondAlert = false;
        }

        scope.hdr = hdr;
        scope.msg = msg;
        scope.action = action;
        scope.alertClass = alertClass;
        scope.disableButtons = disableButtons;
        scope.secondAlert = secondAlert;
        scope.local_backdrop = local_backdrop;

        var modalInstance = $filter('modal')(scope, 'alert.html', 'AlertCtrl', {
            backdrop: local_backdrop
        });

        modalInstance.result.then(function (result) {
            if (result === 'OK') {
                if (typeof secondAlert === 'function') {
                    secondAlert();
                }
            }
        });
    };
}]);

