(function() {
  'use strict';

  angular
    .module('app.core')
    .factory('Alert', Alert);

  Alert.$inject = ['$uibModal'];

  function Alert($uibModal) {
    var service = {
      show: show
    };

    return service;

    function show(options) {
      options = options || {};

      return $uibModal.open({
        animation: true,
        templateUrl: 'app/core/alert/alert.html',
        controller: 'AlertController',
        controllerAs: 'vm',
        size: options.size || 'sm',
        resolve: {
          items: function() {
            return {
              title: options.title,
              message: options.message,
              type: options.type
            };
          }
        }
      }).result;
    }
  }

  AlertController.$inject = ['$uibModalInstance', 'items'];

  function AlertController($uibModalInstance, items) {
    var vm = this;

    vm.title = items.title;
    vm.message = items.message;
    vm.type = items.type;

    vm.ok = function() {
      $uibModalInstance.close();
    };
  }
})();

