        this.checked ? rows.forEach(function(row) {
            row.classList.add('selected');
        }) : rows.forEach(function(row) {
            row.classList.remove('selected');
        });
    }

    function selectAll() {
        this.checked ? checkboxes.forEach(function(checkbox) {
            checkbox.checked = true;
        }) : checkboxes.forEach(function(checkbox) {
            checkbox.checked = false;
        });
    }

    function deselectAll() {
        checkboxes.forEach(function(checkbox) {
            checkbox.checked = false;
        });
    }

    function getSelectedRows() {
        return tbody.querySelectorAll('tr.selected');
    }

    function deleteSelectedRows() {
        var rows = getSelectedRows();
        rows.forEach(function(row) {
            row.parentNode.removeChild(row);
        });
    }

    checkboxes.forEach(function(checkbox) {
        checkbox.addEventListener('change', selectRow);
    });
    var selectAllCheckbox = table.querySelector('.select-all');
    selectAllCheckbox.addEventListener('change', selectAll);
    var selectNoneCheckbox = table.querySelector('.select-none');
    selectNoneCheckbox.addEventListener('change', deselectAll);
    var deleteSelectedButton = table.querySelector('.delete-selected');
    deleteSelectedButton.addEventListener('click', deleteSelectedRows);
    rows.forEach(function(row) {
        var toggleDetailsButton = row.querySelector('.toggle-details');
        if (toggleDetailsButton) {
            toggleDetailsButton.addEventListener('click', toggleRowDetails);
        }
    });
}

