function createCheckbox(element, checked) {
  let li = document.createElement("li");
  li.classList.add("checkbox");
  li.classList.add(checked ? "checked" : "unchecked");
  li.innerHTML = "<input type='checkbox' class='checkbox-input' checked>" + element;
  li.addEventListener("click", (e) => {
    e.stopPropagation();
    li.classList.toggle("checked");
    li.classList.toggle("unchecked");
    li.querySelector(".checkbox-input").checked = !li.querySelector(".checkbox-input").checked;
  });
  return li;
}

