from flask import Blueprint, jsonify, request
from flask_jwt_extended import jwt_required, get_jwt_identity
from .models import Preferences

bp = Blueprint('preferences', __name__)

@bp.route('/', methods=['GET'])
@jwt_required()
def get_preference():
    user_id = get_jwt_identity()
    user = User.query.get(user_id)
    if user is None:
        return jsonify({'error': 'Invalid user'}), 400
    preference = Preferences.query.filter_by(user_id=user_id).first()
    if preference is None:
        return jsonify({'error': 'No preferences found'}), 404
    return jsonify(preference.to_json()), 200

@bp.route('/', methods=['POST'])
@jwt_required()
def create_preference():
    user_id = get_jwt_identity()
    user = User.query.get(user_id)
    if user is None:
        return jsonify({'error': 'Invalid user'}), 400
    preference = Preferences.from_json(request.get_json())
    preference.user_id = user_id
    db.session.add(preference)
    db.session.commit()
    return jsonify(preference.to_json()), 201

@bp.route('/', methods=['PUT'])
@jwt_required()
def update_preference():
    user_id = get_jwt_identity()
    user = User.query.get(user_id)
    if user is None:
        return jsonify({'error': 'Invalid user'}), 400
    preference = Preferences.query.filter_by(user_id=user_id).first()
    if preference is None:
        return jsonify({'error': 'No preferences found'}), 404
    preference.update(request.get_json())
    db.session.commit()
    return jsonify(preference.to_json()), 200

@bp.route('/', methods=['DELETE'])
@jwt_required()
def delete_preference():
    user_id = get_jwt_identity()
    user = User.query.get(user_id)
    if user is None:
        return jsonify({'error': 'Invalid user'}), 400
    preference = Preferences.query.filter_by(user_id=user_id).first()
    if preference is None:
        return jsonify({'error': 'No preferences found'}), 404
    db.session.delete(preference)
    db.session.commit()
    return jsonify({'message': 'Preference deleted'}), 200

