function verify_ssl_cert(ssl_cert_file, ca_file, ca_path) {
  const fs = require('fs');
  const { spawnSync } = require('child_process');
  const openssl = spawnSync('openssl', ['x509', '-in', ssl_cert_file, '-noout', '-text'], {
    encoding: 'utf8',
    stdio: 'pipe',
  });

  if (openssl.status !== 0) {
    console.error(openssl.stderr);
    return false;
  }

  const issuer = /Issuer: CN=(.*)/g.exec(openssl.stdout)[1];
  const subject = /Subject: CN=(.*)/g.exec(openssl.stdout)[1];

  if (issuer === subject) {
    console.error('SSL certificate is self-signed');
    return false;
  }

  const { stdout: issuer_chain } = spawnSync('openssl', ['x509', '-noout', '-issuer', '-in', ssl_cert_file], {
    encoding: 'utf8',
    stdio: 'pipe',
  });

  if (issuer_chain.includes('CN=' + issuer)) {
    console.error('SSL certificate issuer is not trusted');
    return false;
  }

  const { stdout: cert_info } = spawnSync('openssl', ['x509', '-noout', '-in', ssl_cert_file, '-text'], {
    encoding: 'utf8',
    stdio: 'pipe',
  });

  if (cert_info.includes('CA:FALSE')) {
    console.error('SSL certificate is not CA signed');
    return false;
  }

  const { stdout: verify_chain } = spawnSync('openssl', ['verify', '-CAfile', ca_file, '-CApath', ca_path, ssl_cert_file], {
    encoding: 'utf8',
    stdio: 'pipe',
  });

  if (verify_chain.includes('ok')) {
    console.log('SSL certificate is trusted');
    return true;
  } else {
    console.error('SSL certificate is not trusted');
    return false;
  }
}

