function tile(img, options) {
  const tileOptions = {
    width: 100,
    height: 100,
    rows: 2,
    cols: 2,
    margin: 20,
    ...options,
  };

  const canvas = document.createElement('canvas');
  canvas.width = tileOptions.width * tileOptions.cols + tileOptions.margin * (tileOptions.cols - 1);
  canvas.height = tileOptions.height * tileOptions.rows + tileOptions.margin * (tileOptions.rows - 1);
  const ctx = canvas.getContext('2d');

  for (let i = 0; i < tileOptions.rows; i++) {
    for (let j = 0; j < tileOptions.cols; j++) {
      const x = tileOptions.margin + j * (tileOptions.width + tileOptions.margin);
      const y = tileOptions.margin + i * (tileOptions.height + tileOptions.margin);
      ctx.drawImage(img, x, y, tileOptions.width, tileOptions.height);
    }
  }

  return canvas;
}

