function minifyImage(originalFile, minifiedFile, callback) {
    //read the original file and compress it
    fs.readFile(originalFile, (err, data) => {
        if (err) {
            callback(err);
        } else {
            const buffer = zlib.gzipSync(data);
            //write the minified file
            fs.writeFile(minifiedFile, buffer, (err) => {
                if (err) {
                    callback(err);
                } else {
                    callback(null, buffer.length < data.length);
                }
            });
        }
    });
}

