function MatchedLines(props) {
  const repo = props.repo;
  const commit = props.commit;
  const matchedLines = props.matchedLines;
  const baseURL = props.baseURL;
  const filename = props.filename;

  return (
    <div>
      <h2>Matched lines from {filename}</h2>
      <ul>
        {matchedLines.map((matchedLine, index) => (
          <li key={index}>
            <a href={`${baseURL}/blob/${commit}/${filename}#L${matchedLine.start}`}>
              {matchedLine.start}
            </a>
            <span>-</span>
            <a href={`${baseURL}/blob/${commit}/${filename}#L${matchedLine.end}`}>
              {matchedLine.end}
            </a>
          </li>
        ))}
      </ul>
    </div>
  );
}

