import React from "react";
import { Link } from "react-router-dom";
import { useSelector, useDispatch } from "react-redux";
import {
  getQuestions,
  getAnswers,
  getAuthors,
  getLinks,
} from "../redux/selectors";
import { deleteQuestion, deleteAnswer } from "../redux/actions";
import {
  QuestionContainer,
  Question,
  QuestionHeader,
  QuestionBody,
  QuestionAnswers,
  Answer,
  AnswerHeader,
  AnswerBody,
  AnswerLinks,
  AnswerLink,
  DeleteButton,
} from "./Question";

const Questions = () => {
  const questions = useSelector(getQuestions);
  const answers = useSelector(getAnswers);
  const authors = useSelector(getAuthors);
  const links = useSelector(getLinks);
  const dispatch = useDispatch();

  const handleDeleteQuestion = (id) => {
    dispatch(deleteQuestion(id));
  };

  const handleDeleteAnswer = (id) => {
    dispatch(deleteAnswer(id));
  };

  const Questions = () => {
    return (
      <QuestionContainer>
        {questions.map((question) => (
          <Question key={question.id}>
            <QuestionHeader>
              <QuestionBody>
                {question.title}
                <QuestionAnswers>
                  {answers
                    .filter((answer) => answer.question_id === question.id)
                    .map((answer) => (
                      <Answer key={answer.id}>
                        <AnswerHeader>
                          <AnswerBody>
                            {answer.body}
                            {authors[answer.author_id] ? (
                              <img
                                src={authors[answer.author_id].avatar}
                                alt={authors[answer.author_id].name}
                              />
                            ) : null}
                            {links[answer.link_id] ? (
                              <a href={links[answer.link_id].url}>
                                {links[answer.link_id].name}
                              </a>
                            ) : null}
                            <DeleteButton
                              onClick={() => handleDeleteAnswer(answer.id)}
                            >
                              x
                            </DeleteButton>
                          </AnswerBody>
                        </AnswerHeader>
                      </Answer>
                    ))}
                </QuestionAnswers>
                <DeleteButton onClick={() => handleDeleteQuestion(question.id)}>
                  x
                </DeleteButton>
              </QuestionBody>
            </QuestionHeader>
          </Question>
        ))}
      </QuestionContainer>
    );
  };

  return <Questions />;
};

export default Questions;

