import React from "react";
import { Link } from "react-router-dom";
import { connect } from "react-redux";
import { getProfile, getUser } from "../../actions/users";
import { getPages, getPage } from "../../actions/pages";
import { getContributors } from "../../actions/contributors";
import { getLinks } from "../../actions/links";

class UserProfile extends React.Component {
  componentDidMount() {
    const {
      dispatch,
      match: { params },
    } = this.props;
    dispatch(getProfile(params.username));
    dispatch(getUser(params.username));
    dispatch(getPages(params.username));
    dispatch(getContributors(params.username));
    dispatch(getLinks(params.username));
  }

  render() {
    const { user, pages, contributors, links } = this.props;
    const page = pages.find((page) => page.slug === user.slug);
    const { title, description, tags } = page;
    const contributor = contributors.find((contributor) => contributor.id === user.id);
    const link = links.find((link) => link.user === user.id);
    return (
      <div>
        <h1>
          {user.firstName} {user.lastName}
        </h1>
        <p>
          <Link to="/">Back to Home</Link>
        </p>
        <h2>Profile</h2>
        <ul>
          <li>
            <strong>Username:</strong> {user.username}
          </li>
          <li>
            <strong>Email:</strong> {user.email}
          </li>
          <li>
            <strong>First Name:</strong> {user.firstName}
          </li>
          <li>
            <strong>Last Name:</strong> {user.lastName}
          </li>
        </ul>
        <h2>Page</h2>
        <ul>
          <li>
            <strong>Title:</strong> {title}
          </li>
          <li>
            <strong>Description:</strong> {description}
          </li>
          <li>
            <strong>Tags:</strong> {tags}
          </li>
        </ul>
        <h2>Contributors</h2>
        <ul>
          {contributors.map((contributor) => (
            <li key={contributor.id}>
              <strong>Username:</strong> {contributor.username}
            </li>
          ))}
        </ul>
        <h2>Links</h2>
        <ul>
          {links.map((link) => (
            <li key={link.id}>
              <strong>Title:</strong> {link.title}
            </li>
          ))}
        </ul>
      </div>
    );
  }
}

const mapStateToProps = (state, props) => {
  return {
    user: state.users.find((user) => user.username === props.match.params.username),
    pages: state.pages,
    contributors: state.contributors,
    links: state.links,
  };
};

export default connect(mapStateToProps)(UserProfile);

