package main

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strconv"

	_ "github.com/go-sql-driver/mysql"
)

type Tally struct {
	Date string `json:"date"`
	Value int `json:"value"`
}

type Response struct {
	Data []Tally `json:"data"`
}

func handler(w http.ResponseWriter, r *http.Request) {
	// get the URL parameter
	n, err := strconv.Atoi(r.URL.Query().Get("n"))
	if err != nil {
		log.Println(err)
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	// make the connection to the database
	db, err := sql.Open("mysql", "user:password@tcp(localhost:3306)/mydb")
	if err != nil {
		log.Println(err)
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer db.Close()
	// create a slice to hold the results
	var results []Tally
	// make the query
	rows, err := db.Query("SELECT date, value FROM tally WHERE date >= DATE_SUB(CURDATE(), INTERVAL ? DAY)", n)
	if err != nil {
		log.Println(err)
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer rows.Close()
	// populate the results slice
	for rows.Next() {
		var result Tally
		err = rows.Scan(&result.Date, &result.Value)
		if err != nil {
			log.Println(err)
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		results = append(results, result)
	}
	// convert the slice to a JSON array
	js, err := json.Marshal(results)
	if err != nil {
		log.Println(err)
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	// write the JSON array back to the client
	fmt.Fprint(w, string(js))
}

func main() {
	http.HandleFunc("/", handler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}

