import psycopg2

def check_and_create_database(db_name, db_user, db_password, db_host, db_port):
    try:
        conn = psycopg2.connect(
            dbname=db_name,
            user=db_user,
            password=db_password,
            host=db_host,
            port=db_port,
        )
        cur = conn.cursor()
        cur.execute(
            "SELECT datname FROM pg_catalog.pg_database WHERE lower(datname) = lower(%s)",
            (db_name,),
        )
        if not cur.rowcount:
            cur.execute(
                "CREATE DATABASE %s WITH OWNER %s", (db_name, db_user)
            )
        cur.close()
        conn.close()
    except Exception as e:
        print(f"Error: {e}")

