function parseUrlParameters(url) {
  let parameters = url.split('?')[1].split('&');
  let result = {};
  parameters.forEach((parameter) => {
    let [key, value] = parameter.split('=');
    if (key.includes('.')) {
      let keys = key.split('.');
      keys.reduce((previous, current, index, array) => {
        if (index === array.length - 1) {
          previous[current] = value;
        } else {
          if (!previous[current]) {
            previous[current] = {};
          }
        }
        return previous[current];
      }, result);
    } else {
      result[key] = value;
    }
  });
  return result;
}

describe('parseUrlParameters', () => {
  it('should return an object with the URL parameters', () => {
    expect(parseUrlParameters('http://localhost/?a=1&b=2&c=3')).to.deep.equal({
      a: '1',
      b: '2',
      c: '3',
    });
  });
  it('should return an object with the URL parameters in dot notation', () => {
    expect(parseUrlParameters('http://localhost/?a.b.c=1&a.d=2&e=3')).to.deep.equal({
      a: {
        b: {
          c: '1',
        },
        d: '2',
      },
      e: '3',
    });
  });
});

