public class ExtractJarFiles {
  public static void extractJarFiles(String jarFile, String dir) {
    try {
      JarFile jf = new JarFile(jarFile);
      Enumeration<JarEntry> e = jf.entries();

      while (e.hasMoreElements()) {
        JarEntry je = e.nextElement();
        String name = je.getName();
        if (name.startsWith("bin/") && !name.startsWith("bin/META-INF/") && !name.startsWith("bin/META-INF/MANIFEST.MF")) {
          InputStream is = jf.getInputStream(je);
          File f = new File(dir + "/" + name.substring(4));
          File parent = f.getParentFile();
          if (!parent.exists()) {
            parent.mkdirs();
          }
          OutputStream os = new FileOutputStream(f);
          byte[] buffer = new byte[1024];
          int len;
          while ((len = is.read(buffer)) > 0) {
            os.write(buffer, 0, len);
          }
          os.close();
          is.close();
        }
      }
    } catch (IOException e) {
      e.printStackTrace();
    }
  }
}

