def safe_join(directory, *paths):
    """
    Concatenate a directory path with a relative path, raising an error if directory traversal is attempted.
    """
    for path in paths:
        if path.startswith('/') or path.startswith('..'):
            raise ValueError('Absolute or traversal paths not permitted.')
        directory = os.path.normpath(os.path.join(directory, path))
    return directory

