import os
import shutil
import tempfile

def zip_files(subdir):
    """
    Zip all files in a specified subdirectory, excluding .ini files.
    """
    with tempfile.TemporaryDirectory() as tmpdirname:
        for dirpath, _, filenames in os.walk(subdir):
            for filename in filenames:
                if not filename.endswith('.ini'):
                    shutil.make_archive(os.path.join(tmpdirname, filename), 'zip', dirpath)
    return tmpdirname

