import os
import time

def check_resource_limits(accepted_keys, log_dir):
    try:
        cpu_time = os.times()[0]
        virtual_memory = os.statvfs('/').f_bfree
        disk_space = os.statvfs(log_dir).f_bfree
        if cpu_time > 100000000000:
            return False
        elif virtual_memory > 100000000000:
            return False
        elif disk_space > 100000000000:
            return False
        else:
            return True
    except Exception as e:
        print(e)
        return False

