import os
import tarfile

def update_dir_from_tar(tar_file_path, dest_dir):
    # Extract tar contents into dest_dir
    with tarfile.open(tar_file_path, 'r:gz') as tar:
        tar.extractall(dest_dir)

    # Set metadata
    for member in tar.getmembers():
        member.mtime = member.mtime.replace(tzinfo=None)
        member.atime = member.atime.replace(tzinfo=None)
        member.ctime = member.ctime.replace(tzinfo=None)

    # Update file timestamps
    for member in tar.getmembers():
        if member.isfile():
            tar.extract(member, dest_dir)
            os.utime(os.path.join(dest_dir, member.name), (member.atime, member.mtime))

    # Set file permissions
    for member in tar.getmembers():
        if member.isfile():
            os.chmod(os.path.join(dest_dir, member.name), member.mode)

    # Set file ownership
    for member in tar.getmembers():
        if member.isfile():
            os.chown(os.path.join(dest_dir, member.name), member.uid, member.gid)

    return True

