static void AddBookmark(FPDF_DOCUMENT document, int page_number, const char* bookmark_name) {
  FPDF_PAGE page = FPDF_LoadPage(document, page_number);
  FPDF_Dest dest = FPDFDest_Create(page_number, NULL);
  FPDFBookmark_AddDestination(document, bookmark_name, dest);
  FPDF_ClosePage(page);
  FPDFDest_Release(dest);
}

